const i = $input.first().json;
const t = i.tenant || {};
if (!t.business_id) throw new Error('Missing tenant.business_id');
const cust = i.customer || {};
const phone = String(cust.phone || '').replace(/[^0-9]/g, '');
if (!phone) throw new Error('Missing customer.phone');
const items = (Array.isArray(i.items) ? i.items : []).map(it => {
  const qty = parseFloat(it.qty ?? it.quantity ?? 1) || 1;
  const price = parseFloat(it.price ?? it.unit_price ?? 0) || 0;
  return { name: String(it.name ?? 'صنف').trim(), qty, price, line_total: +(qty * price).toFixed(2) };
});
if (items.length === 0) throw new Error('No items');
const subtotal = +items.reduce((s, x) => s + x.line_total, 0).toFixed(2);
const delivery = parseFloat(i.delivery_fee || 0) || 0;
let discount = parseFloat(i.discount_egp || 0) || 0;
if (!discount && i.discount_pct) discount = +(subtotal * (parseFloat(i.discount_pct) / 100)).toFixed(2);
const taxable = +(subtotal + delivery - discount).toFixed(2);
const taxPct = parseFloat(t.tax_pct || 0) || 0;
const tax = +(taxable * taxPct / 100).toFixed(2);
const total = +(taxable + tax).toFixed(2);
const pm = i.payment_method || 'cash';
const now = new Date().toISOString();
const lines = items.map(x => `• ${x.name} × ${x.qty} = ${x.line_total} ج.م`).join('\n');
const pmLabel = ({cash:'💵 كاش عند الاستلام', online:'💳 دفع إلكتروني', transfer:'💰 تحويل بنكي', card:'💳 بطاقة', wallet:'📱 محفظة'})[pm] || ('💰 ' + pm);
let customerMsg = `✅ *تم تأكيد طلبك بنجاح!*\n\n👤 ${cust.name || ''}\n\n📋 *التفاصيل:*\n${lines}\n\n💰 *الحساب:*\n- المجموع: ${subtotal} ج.م\n`;
if (delivery > 0) customerMsg += `- التوصيل: ${delivery} ج.م\n`;
if (discount > 0) customerMsg += `- الخصم: -${discount} ج.م\n`;
if (tax > 0) customerMsg += `- الضريبة (${taxPct}%): ${tax} ج.م\n`;
customerMsg += `- *الإجمالي: ${total} ج.م*\n\n`;
if (i.delivery_address) customerMsg += `📍 ${i.delivery_address}\n`;
customerMsg += `${pmLabel}\n`;
if (i.notes) customerMsg += `📝 ${i.notes}\n`;
customerMsg += `\nنشكر ثقتك في *${t.business_name || ''}* 🌹`;
let adminMsg = `🆕 *طلب جديد*\n\n👤 ${cust.name || ''} | 📱 ${phone}\n`;
if (i.delivery_address) adminMsg += `📍 ${i.delivery_address}\n`;
adminMsg += `\n${lines}\n\n💰 الإجمالي: *${total} ج.م*\n${pmLabel}\n`;
if (i.notes) adminMsg += `📝 ${i.notes}\n`;
adminMsg += `\n🕐 ${now.slice(0,19).replace('T',' ')}`;
const notesFull = [i.notes || '', 'طريقة الدفع: ' + pm].filter(Boolean).join(' | ');
return { json: {
  business_id: t.business_id, instance_name: t.instance_name,
  admin_jid: (t.admin_whatsapp || '') + '@s.whatsapp.net',
  customer_jid: phone + '@s.whatsapp.net', phone, now,
  type: i.type || 'order', items, subtotal, delivery, discount, tax, total,
  delivery_address: i.delivery_address || '', notes_full: notesFull,
  customer_msg: customerMsg, admin_msg: adminMsg,
  customer_body: { business_id: t.business_id, phone, channel: 'whatsapp', last_interaction_at: now, ...(cust.name ? { name: cust.name } : {}) },
  num_body: { b_id: t.business_id }
} };

const p = $('PREPARE').first().json;
const cust = $('UPSERT_CUSTOMER').first().json;
let onum = $json;
if (Array.isArray(onum)) onum = onum[0];
if (onum && typeof onum === 'object') onum = onum.next_order_number ?? onum.value ?? Object.values(onum)[0];
const order_number = (typeof onum === 'string') ? onum : ('ORD-' + Date.now());
return { json: {
  order_number, customer_id: cust.id,
  order_body: { business_id: p.business_id, customer_id: cust.id, order_number, type: p.type,
    items: p.items.map(x => ({ name: x.name, qty: x.qty, price: x.price })),
    subtotal_egp: p.subtotal, delivery_fee_egp: p.delivery, discount_egp: p.discount,
    tax_egp: p.tax, total_egp: p.total, status: 'confirmed',
    delivery_address: p.delivery_address, notes: p.notes_full },
  customer_update_body: { total_orders: (parseInt(cust.total_orders || 0) + 1),
    total_spent_egp: +((parseFloat(cust.total_spent_egp || 0)) + p.total).toFixed(2),
    last_interaction_at: p.now }
} };

const ctx = $('ORDER_CTX').first().json;
const p = $('PREPARE').first().json;
let row = {}; try { row = $('INSERT_ORDER').first().json; if (Array.isArray(row)) row = row[0]; } catch(e){}
return { json: { success: true, order_id: row.id || null, order_number: ctx.order_number,
  total_egp: p.total, currency: 'EGP', message: `تم حفظ الطلب ${ctx.order_number} بإجمالي ${p.total} ج.م` } };
